starterCss:
/* Apply transforms to each box:
   - .rotate: rotate 15 degrees
   - .scale: scale to 1.2x size
   - .skew: skew 10 degrees on X axis */
.transform-demo {
  display: flex;
  gap: 24px;
  padding: 40px;
  justify-content: center;
}
.box {
  width: 120px;
  height: 120px;
  display: flex;
  align-items: center;
  justify-content: center;
  background-color: #4a90d9;
  color: white;
  font-weight: bold;
  border-radius: 8px;
}

